const designImportMigration=require("../../../../../../design_import_migration");const formulaUtils=designImportMigration.getMxgoUtils().moduleFunctions.rosettaFormulaUtils;const _kgb_=designImportMigration.getMxgoUtils().getKgbGlobal();class ActionBarBtnFormulaSnippet{getId(t){let e=[];e.push(t);e.push(_kgb_.modules.utils.getKUID().toString());return e.join("_")}constructor(){this.setDefault()}setDefault(){this.addSnippetAction={id:this.getId("ADD_FORMULA"),codeSnippet:"alert('test')",formulas:{},type:"ADD_FORMULA"}}setAddSnippetCode(t){var e="";var o="";this.addSnippetAction.id=this.getId("ADD_FORMULA");this.addSnippetAction.type="ADD_FORMULA";this.addSnippetAction.formulas={};if(t.code&&t.code.formula){o=t.code.formula}e=formulaUtils.convertFormula(o);var i=formulaUtils.generateNewFormulaId();var n=formulaUtils.generatedFormulaCode(i,e);this.addSnippetAction.codeSnippet="try {\n"+n+"\n} catch(e) { \n console.log(e); alert(e); \n}";this.addSnippetAction.formulas[i]=o}toActions(){return[this.addSnippetAction]}}module.exports={ActionBarBtnFormulaSnippet:ActionBarBtnFormulaSnippet};